def filter_non_empty(strings):
    result = []
    for s in strings:
        cleaned = s.strip()
        if cleaned:
            result.append(cleaned)
    return result

def token_count_simple(text):
    text = text.strip()
    if not text:
        return 0
    return len(text.split())
